import{_ as s,c as a,o as n,d as l}from"./app.661b9247.js";const A=JSON.parse(`{"title":"JavaScript开发调试指导","description":"","frontmatter":{},"headers":[{"level":3,"title":"项目本地以 Debug 模式启动","slug":"项目本地以-debug-模式启动","link":"#项目本地以-debug-模式启动","children":[]},{"level":3,"title":"console.log() 代码打印调试","slug":"console-log-代码打印调试","link":"#console-log-代码打印调试","children":[]},{"level":3,"title":"console.time('time')|console.timeEnd('time') 运行时间打印","slug":"console-time-time-console-timeend-time-运行时间打印","link":"#console-time-time-console-timeend-time-运行时间打印","children":[]}],"relativePath":"Document/DevDebug/JavaScript开发调试/JavaScript开发调试.md","lastUpdated":1670776608000}`),o={name:"Document/DevDebug/JavaScript开发调试/JavaScript开发调试.md"},e=l(`<h1 id="javascript开发调试指导" tabindex="-1">JavaScript开发调试指导 <a class="header-anchor" href="#javascript开发调试指导" aria-hidden="true">#</a></h1><h3 id="项目本地以-debug-模式启动" tabindex="-1">项目本地以 Debug 模式启动 <a class="header-anchor" href="#项目本地以-debug-模式启动" aria-hidden="true">#</a></h3><h3 id="console-log-代码打印调试" tabindex="-1">console.log() 代码打印调试 <a class="header-anchor" href="#console-log-代码打印调试" aria-hidden="true">#</a></h3><p>console.log Console作为 JS 中的一个原生对象，为我们提供了在浏览器控制台进行调试的能力。百分百的前端人都知道console.log()语句，但通过本文的介绍会发现，console.log()真的是一个最熟悉的陌生&#39;人&#39;。 常规用法 console.log()是最为常用的打印输出方法，其可以接收任意类型的内容并输出：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">. </span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;1&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">true</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">null</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">undefined</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">Symbol</span><span style="color:#ABB2BF;">, {</span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;">:</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">}, [</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">], </span><span style="color:#C678DD;">new</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">Set</span><span style="color:#ABB2BF;">(), </span><span style="color:#C678DD;">new</span><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">Date</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>冷门用法 除了常规用法外，console.log()还可以利用以下通配符发挥特殊作用：</p><p>%c：用于添加样式。 可以把输出的语句看做是一个节点，常见的color、font、padding等 css 属性都可以使用。具体用法是在需要添加样式的字符串前加入%c匹配符，紧接着的第二个参数用于定义样式。请看以下示例：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;1231 %c这是你没有见过的console.log&quot;</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&quot;color: #fff; border-radius: 5px; padding: 10px 25px;background: linear-gradient(315deg, #1fd1f9 0%, #b621fe 74%)&quot;</span><span style="color:#ABB2BF;">,</span><span style="color:#98C379;">&#39;1231&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>%o or %O：用于以对象格式打印。 在字符串中加入%o 或者 %O，可以将字符串后紧接着的对象插入到字符串中。请看示例：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;一串%o字符&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">$0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>另外呢，%o 和%O也有一定的差别，%O的作用更像console.dir:</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;一串%o字符&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">$0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;一串%O字符&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">$0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>%d or %i：用于将数字输出为整数。 %d or %i可以将其之后紧随的字符作为整数输出，类似于toFixed(0)：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;输出为整数%i&#39;</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">1.99</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>转换类数字的字符串也是可以的：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;输出为整数%i&#39;</span><span style="color:#ABB2BF;">,</span><span style="color:#98C379;">&#39;1.99&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其余的转换逻辑其实与 js 是一样的：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;输出为整数%i&#39;</span><span style="color:#ABB2BF;">,</span><span style="color:#98C379;">&#39;aa1.99&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>%s：用于打印字符串。 %s可以将其之后紧随的任意类型的值作为字符串输出，类似于 js 中的字符串拼接：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;类似于字符串拼接%s&#39;</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">123</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;类似于字符串拼接%s&#39;</span><span style="color:#ABB2BF;">,[</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">])</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;类似于字符串拼接%s&#39;</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">null</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;类似于字符串拼接%s&#39;</span><span style="color:#ABB2BF;">,{})</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>%f：用于格式化打印浮点数。 %f可以将其之后紧随的任意类型的值作为浮点数输出，可以通过%.2f这样的形式来指定需要格式化的位数：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;浮点数格式化 %f&quot;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;浮点数格式化 %.3f&quot;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">1.232323</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>值得注意的是，该语法在chrome及edge中并不会生效。</p><h3 id="console-time-time-console-timeend-time-运行时间打印" tabindex="-1">console.time(&#39;time&#39;)|console.timeEnd(&#39;time&#39;) 运行时间打印 <a class="header-anchor" href="#console-time-time-console-timeend-time-运行时间打印" aria-hidden="true">#</a></h3><p>其他： 从206个console.log()完全弄懂数据类型转换的前世今生(下)： 5分钟教你使用 console.log 输出五彩斑斓的黑：<a href="https://juejin.cn/post/7087192401978064933" target="_blank" rel="noreferrer">https://juejin.cn/post/7087192401978064933</a> 你应该会的前端Debug技能：<a href="https://juejin.cn/post/7084924971901779998" target="_blank" rel="noreferrer">https://juejin.cn/post/7084924971901779998</a></p>`,25),p=[e];function c(r,t,i,B,d,y){return n(),a("div",null,p)}const F=s(o,[["render",c]]);export{A as __pageData,F as default};
